// RegisterUser creates a new user profile and inserts it into the database.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	user := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
		CreatedAt:   time.Now(),
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id

	return user, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Build the SQL query with parameter placeholders
	query := `
		SELECT u.display_name, a.action_type, 
			COUNT(*) as total_actions, 
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
			AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (?`

	// Add more placeholders for usernames
	for i := 1; i < len(usernames); i++ {
		query += ", ?"
	}
	query += ") AND a.created_at BETWEEN ? AND ?"

	// Add action type filter if specified
	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
	}

	query += " GROUP BY u.display_name, a.action_type"

	// Prepare parameters
	params := make([]interface{}, 0, len(usernames)+3)
	for _, username := range usernames {
		params = append(params, username)
	}
	params = append(params, startDate)
	params = append(params, endDate)
	if actionTypeFilter != "" {
		params = append(params, actionTypeFilter)
	}

	// Execute query
	var results []UserActivitySummary
	_, err := o.Raw(query, params...).QueryRows(&results)
	if err != nil {
		return nil, err
	}

	return results, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	// Validate groupByField
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, errors.New("invalid groupByField. Must be one of: department, role, display_name")
	}

	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	// Build the SQL query
	query := fmt.Sprintf(`
		SELECT %s as group_value, 
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (?`, groupByField)

	// Add more placeholders for departments
	for i := 1; i < len(departments); i++ {
		query += ", ?"
	}
	query += fmt.Sprintf(") GROUP BY %s", groupByField)

	// Prepare parameters
	params := make([]interface{}, len(departments))
	for i, dept := range departments {
		params[i] = dept
	}

	// Execute query
	var rows []orm.Params
	_, err := o.Raw(query, params...).Values(&rows)
	if err != nil {
		return nil, err
	}

	// Convert to []map[string]interface{}
	result := make([]map[string]interface{}, len(rows))
	for i, row := range rows {
		result[i] = map[string]interface{}{
			"group_value":       row["group_value"],
			"user_count":        row["user_count"],
			"total_activities":  row["total_activities"],
		}
	}

	return result, nil
}

